import os
import shlex
import subprocess

ALLOWED_EXTENSIONS = {
    "jpg", "jpeg", "png", "gif", "webp", "bmp", "tiff", "tif", "avif", "heic", "heif"
}

DEFAULT_OUTPUT_FORMAT = "png"
TMP_DIR = "/tmp"


def _safe_basename(name: str) -> str:
    return os.path.basename(name).replace("\x00", "")


def _safe_ext(ext: str) -> str:
    ext = (ext or "").lower().lstrip(".")
    return ext if ext in ALLOWED_EXTENSIONS else DEFAULT_OUTPUT_FORMAT


def _build_output_path(input_name: str, output_format: str) -> str:
    base = os.path.splitext(_safe_basename(input_name))[0] or "image"
    return os.path.join(TMP_DIR, f"{base}.{output_format}")


def convert_image(event, context):
    name = event.get("name", "")
    metadata = event.get("metadata") or {}

    source_name = _safe_basename(metadata.get("source_filename") or name)
    if not source_name:
        raise ValueError("Missing source filename")

    output_format = _safe_ext(metadata.get("output_format", DEFAULT_OUTPUT_FORMAT))
    resize = metadata.get("resize")
    quality = metadata.get("quality")
    rotate = metadata.get("rotate")

    input_path = os.path.join(TMP_DIR, source_name)
    output_path = _build_output_path(source_name, output_format)

    cmd = ["convert", input_path]

    if resize:
        cmd.extend(["-resize", str(resize)])
    if quality:
        cmd.extend(["-quality", str(quality)])
    if rotate:
        cmd.extend(["-rotate", str(rotate)])

